public class BinarySearch {
    static int search(int[] arr, int target) {
        int lo = 0, hi = arr.length;
        while (lo < hi) {
            int mid = (lo + hi) / 2;
            if (arr[mid] == target) return mid;
            if (arr[mid] < target) lo = mid;   // bug: should be mid + 1
            else hi = mid;
        }
        return -1;
    }
}
